     1→const express = require('express');
     2→const router = express.Router();
     3→const pool = require('../lib/db');
     4→const { authMiddleware } = require('../lib/auth');
     5→const { chat } = require('../lib/polsia-ai');
     6→const omniscoreService = require('../services/omniscore');
     7→
     8→// Skill catalog - available to all candidates without pre-existing skills
     9→const SKILL_CATALOG = [
    10→  { name: 'JavaScript', category: 'technical', icon: 'JS', description: 'Core JS, ES6+, async/await, closures, prototypes', difficulty: 'Adaptive' },
    11→  { name: 'Python', category: 'technical', icon: 'PY', description: 'Core Python, data structures, OOP, standard library', difficulty: 'Adaptive' },
    12→  { name: 'React', category: 'technical', icon: 'RE', description: 'Components, hooks, state management, lifecycle', difficulty: 'Adaptive' },
    13→  { name: 'Node.js', category: 'technical', icon: 'NJ', description: 'Express, APIs, async patterns, middleware', difficulty: 'Adaptive' },
    14→  { name: 'SQL', category: 'technical', icon: 'SQL', description: 'Queries, joins, indexing, optimization, transactions', difficulty: 'Adaptive' },
    15→  { name: 'TypeScript', category: 'technical', icon: 'TS', description: 'Types, interfaces, generics, type guards', difficulty: 'Adaptive' },
    16→  { name: 'Java', category: 'technical', icon: 'JV', description: 'OOP, collections, multithreading, design patterns', difficulty: 'Adaptive' },
    17→  { name: 'CSS & HTML', category: 'technical', icon: 'CSS', description: 'Flexbox, Grid, responsive design, accessibility', difficulty: 'Adaptive' },
    18→  { name: 'AWS', category: 'technical', icon: 'AWS', description: 'EC2, S3, Lambda, IAM, CloudFormation', difficulty: 'Adaptive' },
    19→  { name: 'Docker', category: 'technical', icon: 'DK', description: 'Containers, images, compose, networking', difficulty: 'Adaptive' },
    20→  { name: 'Git', category: 'technical', icon: 'GIT', description: 'Branching, merging, rebasing, workflows', difficulty: 'Adaptive' },
    21→  { name: 'Data Analysis', category: 'analytical', icon: 'DA', description: 'Statistics, visualization, pandas, Excel formulas', difficulty: 'Adaptive' },
    22→  { name: 'System Design', category: 'technical', icon: 'SD', description: 'Scalability, databases, caching, load balancing', difficulty: 'Adaptive' },
    23→  { name: 'Project Management', category: 'soft_skill', icon: 'PM', description: 'Agile, planning, risk management, stakeholders', difficulty: 'Adaptive' },
    24→  { name: 'Communication', category: 'soft_skill', icon: 'CM', description: 'Written, verbal, presentation, feedback', difficulty: 'Adaptive' },
    25→  { name: 'Machine Learning', category: 'technical', icon: 'ML', description: 'Algorithms, neural networks, training, evaluation', difficulty: 'Adaptive' },
    26→];
    27→
    28→// Get skill catalog with user's assessment history
    29→router.get('/available', authMiddleware, async (req, res) => {
    30→  try {
    31→    const userId = req.user.id;
    32→
    33→    // Get user's existing skills and assessment data
    34→    const userSkillsResult = await pool.query(`
    35→      SELECT cs.id, cs.skill_name, cs.category, cs.level, cs.is_verified, cs.verified_score,
    36→             COUNT(sa.id) as assessment_count,
    37→             MAX(sa.score) as best_score,
    38→             MAX(sa.completed_at) as last_attempted
    39→      FROM candidate_skills cs
    40→      LEFT JOIN skill_assessments sa ON cs.id = sa.skill_id AND sa.completed_at IS NOT NULL
    41→      WHERE cs.user_id = $1
    42→      GROUP BY cs.id
    43→      ORDER BY cs.is_verified ASC, cs.created_at DESC
    44→    `, [userId]);
    45→
    46→    const userSkillMap = {};
    47→    for (const skill of userSkillsResult.rows) {
    48→      userSkillMap[skill.skill_name.toLowerCase()] = skill;
    49→    }
    50→
    51→    // Build catalog with user's data overlaid
    52→    const catalog = SKILL_CATALOG.map(catalogSkill => {
    53→      const userSkill = userSkillMap[catalogSkill.name.toLowerCase()];
    54→      return {
    55→        catalog_name: catalogSkill.name,
    56→        category: catalogSkill.category,
    57→        icon: catalogSkill.icon,
    58→        description: catalogSkill.description,
    59→        difficulty: catalogSkill.difficulty,
    60→        // User-specific data
    61→        skill_id: userSkill ? userSkill.id : null,
    62→        is_verified: userSkill ? userSkill.is_verified : false,
    63→        verified_score: userSkill ? userSkill.verified_score : null,
    64→        assessment_count: userSkill ? parseInt(userSkill.assessment_count) : 0,
    65→        best_score: userSkill ? userSkill.best_score : null,
    66→        last_attempted: userSkill ? userSkill.last_attempted : null,
    67→      };
    68→    });
    69→
    70→    // Also include any user skills NOT in the catalog
    71→    for (const skill of userSkillsResult.rows) {
    72→      const inCatalog = SKILL_CATALOG.some(c => c.name.toLowerCase() === skill.skill_name.toLowerCase());
    73→      if (!inCatalog) {
    74→        catalog.push({
    75→          catalog_name: skill.skill_name,
    76→          category: skill.category,
    77→          icon: skill.skill_name.substring(0, 2).toUpperCase(),
    78→          description: `Custom skill: ${skill.skill_name}`,
    79→          difficulty: 'Adaptive',
    80→          skill_id: skill.id,
    81→          is_verified: skill.is_verified,
    82→          verified_score: skill.verified_score,
    83→          assessment_count: parseInt(skill.assessment_count),
    84→          best_score: skill.best_score,
    85→          last_attempted: skill.last_attempted,
    86→        });
    87→      }
    88→    }
    89→
    90→    res.json({ skills: catalog });
    91→  } catch (error) {
    92→    console.error('Error fetching available assessments:', error);
    93→    res.status(500).json({ error: 'Failed to fetch assessments' });
    94→  }
    95→});
    96→
    97→// Get past assessment results
    98→router.get('/results', authMiddleware, async (req, res) => {
    99→  try {
   100→    const userId = req.user.id;
   101→
   102→    const result = await pool.query(`
   103→      SELECT sa.*, cs.skill_name, cs.category,
   104→             ass.tab_switches, ass.copy_paste_attempts, ass.time_anomalies,
   105→             ass.max_difficulty_reached, ass.answers_given
   106→      FROM skill_assessments sa
   107→      LEFT JOIN candidate_skills cs ON sa.skill_id = cs.id
   108→      LEFT JOIN assessment_sessions ass ON sa.session_id = ass.id
   109→      WHERE sa.user_id = $1 AND sa.completed_at IS NOT NULL
   110→      ORDER BY sa.completed_at DESC
   111→    `, [userId]);
   112→
   113→    res.json({ results: result.rows });
   114→  } catch (error) {
   115→    console.error('Error fetching assessment results:', error);
   116→    res.status(500).json({ error: 'Failed to fetch results' });
   117→  }
   118→});
   119→
   120→// Start new assessment - accepts skillName+category OR skillId
   121→router.post('/start', authMiddleware, async (req, res) => {
   122→  const client = await pool.connect();
   123→  try {
   124→    const userId = req.user.id;
   125→    const { skillId, skillName, category, jobId } = req.body;
   126→
   127→    await client.query('BEGIN');
   128→
   129→    let skill;
   130→
   131→    if (skillId) {
   132→      // Legacy: lookup by ID
   133→      const skillResult = await client.query(
   134→        'SELECT * FROM candidate_skills WHERE id = $1 AND user_id = $2',
   135→        [skillId, userId]
   136→      );
   137→      skill = skillResult.rows[0];
   138→    }
   139→
   140→    if (!skill && skillName) {
   141→      // Look up or auto-create the skill in candidate_skills
   142→      const existingResult = await client.query(
   143→        'SELECT * FROM candidate_skills WHERE user_id = $1 AND LOWER(skill_name) = LOWER($2)',
   144→        [userId, skillName]
   145→      );
   146→
   147→      if (existingResult.rows.length > 0) {
   148→        skill = existingResult.rows[0];
   149→      } else {
   150→        // Auto-create the skill for this user
   151→        const insertResult = await client.query(`
   152→          INSERT INTO candidate_skills (user_id, skill_name, category, level)
   153→          VALUES ($1, $2, $3, 1)
   154→          RETURNING *
   155→        `, [userId, skillName, category || 'technical']);
   156→        skill = insertResult.rows[0];
   157→      }
   158→    }
   159→
   160→    if (!skill) {
   161→      await client.query('ROLLBACK');
   162→      return res.status(400).json({ error: 'Skill name or ID required' });
   163→    }
   164→
   165→    // Check for active session
   166→    const activeSession = await client.query(
   167→      "SELECT id FROM assessment_sessions WHERE user_id = $1 AND skill_id = $2 AND status = 'in_progress'",
   168→      [userId, skill.id]
   169→    );
   170→    if (activeSession.rows.length > 0) {
   171→      // Abandon old session
   172→      await client.query(
   173→        "UPDATE assessment_sessions SET status = 'abandoned' WHERE id = $1",
   174→        [activeSession.rows[0].id]
   175→      );
   176→    }
   177→
   178→    // Create assessment session
   179→    const sessionResult = await client.query(`
   180→      INSERT INTO assessment_sessions
   181→      (user_id, skill_id, job_id, status, current_difficulty, current_question_index, score,
   182→       max_difficulty_reached, tab_switches, copy_paste_attempts, time_anomalies,
   183→       questions_asked, answers_given, started_at)
   184→      VALUES ($1, $2, $3, 'in_progress', 2, 0, 0, 2, 0, 0, 0, '[]'::jsonb, '[]'::jsonb, NOW())
   185→      RETURNING *
   186→    `, [userId, skill.id, jobId || null]);
   187→
   188→    const session = sessionResult.rows[0];
   189→
   190→    // Generate first question
   191→    const question = await generateQuestion(skill.skill_name, skill.category, 2, client);
   192→
   193→    if (!question) {
   194→      await client.query('ROLLBACK');
   195→      return res.status(500).json({ error: 'Failed to generate questions. Please try again.' });
   196→    }
   197→
   198→    // Record question asked
   199→    const questionsAsked = [{ questionId: question.id, difficulty: question.difficulty_level, timestamp: new Date() }];
   200→    await client.query(
   201→      'UPDATE assessment_sessions SET questions_asked = $1, current_question_index = 1 WHERE id = $2',
   202→      [JSON.stringify(questionsAsked), session.id]
   203→    );
   204→
   205→    await client.query('COMMIT');
   206→
   207→    res.json({
   208→      sessionId: session.id,
   209→      skillName: skill.skill_name,
   210→      question: {
   211→        id: question.id,
   212→        text: question.question_text,
   213→        type: question.question_type,
   214→        options: typeof question.options === 'string' ? JSON.parse(question.options) : question.options,
   215→        timeLimit: question.time_limit_seconds || 120,
   216→        questionNumber: 1,
   217→        totalQuestions: 10
   218→      }
   219→    });
   220→  } catch (error) {
   221→    await client.query('ROLLBACK');
   222→    console.error('Error starting assessment:', error);
   223→    res.status(500).json({ error: 'Failed to start assessment' });
   224→  } finally {
   225→    client.release();
   226→  }
   227→});
   228→
   229→// Submit answer and get next question
   230→router.post('/answer', authMiddleware, async (req, res) => {
   231→  const client = await pool.connect();
   232→  try {
   233→    const userId = req.user.id;
   234→    const { sessionId, questionId, answer, timeTaken } = req.body;
   235→
   236→    await client.query('BEGIN');
   237→
   238→    // Get session
   239→    const sessionResult = await client.query(
   240→      'SELECT * FROM assessment_sessions WHERE id = $1 AND user_id = $2',
   241→      [sessionId, userId]
   242→    );
   243→
   244→    if (sessionResult.rows.length === 0) {
   245→      await client.query('ROLLBACK');
   246→      return res.status(404).json({ error: 'Session not found' });
   247→    }
   248→
   249→    const session = sessionResult.rows[0];
   250→
   251→    if (session.status !== 'in_progress') {
   252→      await client.query('ROLLBACK');
   253→      return res.status(400).json({ error: 'Session is not active' });
   254→    }
   255→
   256→    // Get question details
   257→    const questionResult = await client.query(
   258→      'SELECT * FROM assessment_questions WHERE id = $1',
   259→      [questionId]
   260→    );
   261→
   262→    if (questionResult.rows.length === 0) {
   263→      await client.query('ROLLBACK');
   264→      return res.status(404).json({ error: 'Question not found' });
   265→    }
   266→
   267→    const question = questionResult.rows[0];
   268→
   269→    // Evaluate answer
   270→    let isCorrect = false;
   271→    let scorePoints = 0;
   272→    let aiFeedback = null;
   273→
   274→    if (question.question_type === 'multiple_choice') {
   275→      isCorrect = answer === question.correct_answer;
   276→      scorePoints = isCorrect ? (question.difficulty_level || 2) * 10 : 0;
   277→    } else if (question.question_type === 'short_answer') {
   278→      // Use AI to evaluate short answer
   279→      const evaluation = await evaluateShortAnswer(question.question_text, answer, question.explanation);
   280→      isCorrect = evaluation.score >= 70;
   281→      scorePoints = Math.round((evaluation.score / 100) * (question.difficulty_level || 2) * 15);
   282→      aiFeedback = evaluation.feedback;
   283→    }
   284→
   285→    // Check for time anomaly (too fast)
   286→    const expectedMinTime = question.question_type === 'multiple_choice' ? 5 : 15;
   287→    const isTimeAnomaly = timeTaken < expectedMinTime;
   288→
   289→    // Update session
   290→    const questionsAsked = typeof session.questions_asked === 'string'
   291→      ? JSON.parse(session.questions_asked) : (session.questions_asked || []);
   292→    const answersGiven = typeof session.answers_given === 'string'
   293→      ? JSON.parse(session.answers_given) : (session.answers_given || []);
   294→
   295→    answersGiven.push({
   296→      questionId,
   297→      answer,
   298→      isCorrect,
   299→      scorePoints,
   300→      timeTaken,
   301→      timestamp: new Date(),
   302→      aiFeedback
   303→    });
   304→
   305→    const newScore = (session.score || 0) + scorePoints;
   306→    const currentQuestionIndex = (session.current_question_index || 0) + 1;
   307→
   308→    // Adaptive difficulty: increase if correct and no time anomaly, decrease if wrong
   309→    let newDifficulty = session.current_difficulty || 2;
   310→    if (isCorrect && !isTimeAnomaly && newDifficulty < 5) {
   311→      newDifficulty += 1;
   312→    } else if (!isCorrect && newDifficulty > 1) {
   313→      newDifficulty -= 1;
   314→    }
   315→
   316→    const maxDifficultyReached = Math.max(session.max_difficulty_reached || 2, newDifficulty);
   317→    const timeAnomalies = (session.time_anomalies || 0) + (isTimeAnomaly ? 1 : 0);
   318→
   319→    await client.query(`
   320→      UPDATE assessment_sessions
   321→      SET answers_given = $1, score = $2, current_question_index = $3,
   322→          current_difficulty = $4, max_difficulty_reached = $5,
   323→          time_anomalies = $6
   324→      WHERE id = $7
   325→    `, [
   326→      JSON.stringify(answersGiven), newScore, currentQuestionIndex,
   327→      newDifficulty, maxDifficultyReached, timeAnomalies, sessionId
   328→    ]);
   329→
   330→    // Check if assessment is complete (10 questions)
   331→    if (currentQuestionIndex >= 10) {
   332→      await completeAssessment(client, sessionId, userId);
   333→      await client.query('COMMIT');
   334→
   335→      return res.json({
   336→        completed: true,
   337→        score: newScore,
   338→        feedback: isCorrect ? 'Correct!' : 'Incorrect',
   339→        explanation: question.explanation,
   340→        aiFeedback
   341→      });
   342→    }
   343→
   344→    // Get skill for next question
