   445→// Helper: Generate or fetch question
   446→async function generateQuestion(skillName, category, difficulty, client) {
   447→  // Try to find existing question from bank
   448→  const existingResult = await client.query(`
   449→    SELECT * FROM assessment_questions
   450→    WHERE LOWER(skill_category) = LOWER($1) AND difficulty_level = $2
   451→    ORDER BY RANDOM()
   452→    LIMIT 1
   453→  `, [skillName, difficulty]);
   454→
   455→  if (existingResult.rows.length > 0) {
   456→    return existingResult.rows[0];
   457→  }
   458→
   459→  // Generate new question using AI
   460→  const questionType = Math.random() > 0.3 ? 'multiple_choice' : 'short_answer';
   461→  const prompt = `Generate a difficulty ${difficulty}/5 technical assessment question about "${skillName}" (category: ${category}).
   462→
   463→Question type: ${questionType}
   464→
   465→Return ONLY valid JSON (no markdown, no code blocks):
   466→{
   467→  "question_text": "The question text here",
   468→  "question_type": "${questionType}",
   469→  ${questionType === 'multiple_choice' ? '"options": ["Option A text", "Option B text", "Option C text", "Option D text"],\n  "correct_answer": "Option A text",' : ''}
   470→  "explanation": "Brief explanation of the correct answer",
   471→  "time_limit_seconds": ${questionType === 'multiple_choice' ? '90' : '180'}
   472→}
   473→
   474→Requirements:
   475→- Make it practical and relevant to real-world ${skillName} work
   476→- Difficulty ${difficulty}/5 (1=beginner, 5=expert)
   477→- ${questionType === 'multiple_choice' ? 'Provide exactly 4 options. correct_answer must exactly match one of the options.' : 'Ask a question that requires a detailed written response.'}
   478→- Keep question clear and unambiguous`;
   479→
   480→  try {
   481→    const response = await chat(prompt, { maxTokens: 1024, module: 'assessments', feature: 'question_generation' });
   482→
   483→    // Parse response - handle potential markdown code blocks
   484→    let cleanResponse = response.trim();
   485→    if (cleanResponse.startsWith('```')) {
   486→      cleanResponse = cleanResponse.replace(/^```(?:json)?\s*/, '').replace(/\s*```$/, '');
   487→    }
   488→
   489→    const questionData = JSON.parse(cleanResponse);
   490→
   491→    // Validate the response
   492→    if (!questionData.question_text) {
   493→      throw new Error('Missing question_text in AI response');
   494→    }
   495→
   496→    const qType = questionData.question_type || questionType;
   497→    const options = qType === 'multiple_choice' && questionData.options
   498→      ? (typeof questionData.options === 'string' ? questionData.options : JSON.stringify(questionData.options))
   499→      : null;
   500→
   501→    // Save to database
   502→    const result = await client.query(`
   503→      INSERT INTO assessment_questions
   504→      (skill_category, difficulty_level, question_type, question_text, options, correct_answer, explanation, time_limit_seconds)
   505→      VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
   506→      RETURNING *
   507→    `, [
   508→      skillName,
   509→      difficulty,
   510→      qType,
   511→      questionData.question_text,
   512→      options,
   513→      questionData.correct_answer || null,
   514→      questionData.explanation || 'See the correct answer above.',
   515→      questionData.time_limit_seconds || (qType === 'multiple_choice' ? 90 : 180)
   516→    ]);
   517→
   518→    return result.rows[0];
   519→  } catch (error) {
   520→    console.error('Error generating AI question:', error);
   521→
   522→    // Fallback: try any question from the bank
   523→    const fallbackResult = await client.query(`
   524→      SELECT * FROM assessment_questions
   525→      ORDER BY RANDOM()
   526→      LIMIT 1
   527→    `);
   528→
   529→    if (fallbackResult.rows.length > 0) {
   530→      return fallbackResult.rows[0];
   531→    }
   532→
   533→    // Last resort: create a hardcoded question
   534→    const fallbackInsert = await client.query(`
   535→      INSERT INTO assessment_questions
   536→      (skill_category, difficulty_level, question_type, question_text, options, correct_answer, explanation, time_limit_seconds)
   537→      VALUES ($1, $2, 'multiple_choice', $3, $4, $5, $6, 90)
   538→      RETURNING *
   539→    `, [
   540→      skillName,
   541→      difficulty,
   542→      `Which of the following best describes a key concept in ${skillName}?`,
   543→      JSON.stringify([
   544→        `A fundamental principle of ${skillName} that enables modularity`,
   545→        `A deprecated feature that is no longer recommended`,
   546→        `A testing framework specific to ${skillName}`,
   547→        `A build tool used exclusively in ${skillName} projects`
   548→      ]),
   549→      `A fundamental principle of ${skillName} that enables modularity`,
   550→      `Understanding core principles is essential for working effectively with ${skillName}.`
   551→    ]);
   552→    return fallbackInsert.rows[0];
   553→  }
   554→}
