   819→// Recruiter: Get all assessment results across all candidates
   820→router.get('/recruiter/all', authMiddleware, async (req, res) => {
   821→  try {
   822→    const recruiterRoles = ['employer', 'recruiter', 'hiring_manager', 'admin'];
   823→    if (!recruiterRoles.includes(req.user.role)) {
   824→      return res.status(403).json({ error: 'Recruiter access required' });
   825→    }
   826→
   827→    const { skill, status, sort } = req.query;
   828→
   829→    let query = `
   830→      SELECT sa.id, sa.score, sa.max_score, sa.passed, sa.anti_cheat_score,
   831→             sa.duration_seconds, sa.completed_at, sa.title,
   832→             cs.skill_name, cs.category, cs.is_verified,
   833→             ass.max_difficulty_reached, ass.tab_switches, ass.copy_paste_attempts,
   834→             u.name as candidate_name, u.email as candidate_email, u.id as candidate_id
   835→      FROM skill_assessments sa
   836→      LEFT JOIN candidate_skills cs ON sa.skill_id = cs.id
   837→      LEFT JOIN assessment_sessions ass ON sa.session_id = ass.id
   838→      LEFT JOIN users u ON sa.user_id = u.id
   839→      WHERE sa.completed_at IS NOT NULL
   840→    `;
   841→    const params = [];
   842→    let paramIdx = 1;
   843→
   844→    if (skill) {
   845→      query += ` AND LOWER(cs.skill_name) = LOWER($${paramIdx})`;
   846→      params.push(skill);
   847→      paramIdx++;
   848→    }
   849→
   850→    if (status === 'passed') {
   851→      query += ` AND sa.passed = true`;
   852→    } else if (status === 'failed') {
   853→      query += ` AND sa.passed = false`;
   854→    }
   855→
   856→    if (sort === 'score_desc') {
   857→      query += ` ORDER BY sa.score DESC`;
   858→    } else if (sort === 'score_asc') {
   859→      query += ` ORDER BY sa.score ASC`;
   860→    } else {
   861→      query += ` ORDER BY sa.completed_at DESC`;
   862→    }
   863→
   864→    query += ` LIMIT 100`;
   865→
   866→    const result = await pool.query(query, params);
   867→
   868→    // Also get summary stats
   869→    const statsResult = await pool.query(`
   870→      SELECT
   871→        COUNT(DISTINCT sa.user_id) as total_candidates,
   872→        COUNT(*) as total_assessments,
   873→        COUNT(*) FILTER (WHERE sa.passed = true) as total_passed,
   874→        ROUND(AVG(sa.score), 1) as avg_score,
   875→        COUNT(DISTINCT cs.skill_name) as skills_tested
   876→      FROM skill_assessments sa
   877→      LEFT JOIN candidate_skills cs ON sa.skill_id = cs.id
   878→      WHERE sa.completed_at IS NOT NULL
   879→    `);
   880→
   881→    // Get skill breakdown
   882→    const skillBreakdown = await pool.query(`
   883→      SELECT cs.skill_name, cs.category,
   884→             COUNT(*) as attempt_count,
   885→             COUNT(*) FILTER (WHERE sa.passed = true) as pass_count,
   886→             ROUND(AVG(sa.score), 1) as avg_score
   887→      FROM skill_assessments sa
   888→      LEFT JOIN candidate_skills cs ON sa.skill_id = cs.id
   889→      WHERE sa.completed_at IS NOT NULL
