                          {app.cover_letter && <FileText className="h-2.5 w-2.5" />}
                        </div>
                        {/* Quick advance button */}
                        {stage !== 'hired' && (
                          <Button
                            variant="ghost"
                            size="sm"
                            className="w-full mt-1.5 h-6 text-[10px] gap-1 text-muted-foreground hover:text-primary"
