                                updateStatus(app.id, kanbanStages[nextIdx])
                              }
                            }}
                          >
                            <ChevronRight className="h-3 w-3" />
                            Advance
                          </Button>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              )
